template.script:
                document.addEventListener('DOMContentLoaded', function () {
                    // Handle delete report button
                    document.querySelectorAll('.delete-report-btn').forEach(function(btn) {
                        btn.addEventListener('click', function() {
                            const batchId = this.getAttribute('data-batch-id');
                            if (!batchId) {
                                alert('Batch ID not found');
                                return;
                            }

                            if (confirm('Are you sure you want to delete this progress report? This action cannot be undone.')) {
                                // Show loading state
                                const originalText = this.innerHTML;
                                this.disabled = true;
                                this.innerHTML = ' Deleting...';

                                fetch('/my/progress_reports/delete/' + batchId, {
                                    method: 'POST',
                                    headers: {
                                        'Content-Type': 'application/json',
                                    },
                                    body: JSON.stringify({
                                        jsonrpc: '2.0',
                                        method: 'call',
                                        params: {},
                                        id: Math.floor(Math.random() * 1000000)
                                    }),
                                    credentials: 'same-origin'
                                })
                                .then(response => response.json())
                                .then(function(data) {
                                    var result = data.result || data;
                                    if (result.success) {
                                        // Reload the page to show updated list
                                        window.location.reload();
                                    } else {
                                        alert('Error deleting report: ' + (result.error || 'Unknown error'));
                                        btn.disabled = false;
                                        btn.innerHTML = originalText;
                                    }
                                })
                                .catch(function(error) {
                                    console.error('Error deleting report:', error);
                                    alert('Error deleting report. Please try again.');
                                    btn.disabled = false;
                                    btn.innerHTML = originalText;
                                });
                            }
                        });
                    });

                    // Override breadcrumb to show only Home / Progress Report
                    const breadcrumb = document.querySelector('.o_portal_submenu.breadcrumb');
                    if (breadcrumb) {
                        // Clear existing breadcrumb items
                        breadcrumb.innerHTML = '';
                        // Add home icon
                        const homeItem = document.createElement('li');
                        homeItem.className = 'breadcrumb-item';
                        homeItem.innerHTML = '';
                        breadcrumb.appendChild(homeItem);
                        // Add Progress Report
                        const reportItem = document.createElement('li');
                        reportItem.className = 'breadcrumb-item active';
                        reportItem.setAttribute('aria-current', 'page');
                        reportItem.textContent = 'Progress Report';
                        breadcrumb.appendChild(reportItem);
                    }

                    // Show/hide timesheet section based on task selection
                    function toggleTimesheetSection(row) {
                        const mainTaskSelect = row.querySelector('.main-task-select');
                        const subtaskSelect = row.querySelector('.subtask-select');
                        const timesheetSection = row.querySelector('.timesheet-section');
                        const timesheetDateInput = row.querySelector('.timesheet-date');
                        const globalDateInput = document.querySelector('#global-date-input');

                        // Show timesheet section if main task is selected (regardless of subtask)
                        if (mainTaskSelect && mainTaskSelect.value) {
                            if (timesheetSection) {
                                timesheetSection.style.display = 'block';
                            }
                            // Set timesheet date to global date if not already set
                            if (timesheetDateInput && globalDateInput && globalDateInput.value && !timesheetDateInput.value) {
                                timesheetDateInput.value = globalDateInput.value;
                            }
                        } else {
                            if (timesheetSection) {
                                timesheetSection.style.display = 'none';
                            }
                        }
                    }

                    // Initialize timesheet sections for existing rows
                    document.querySelectorAll('.task-row').forEach(row => {
                        toggleTimesheetSection(row);
                    });

                    // Add event listeners for main task and subtask changes
                    document.querySelectorAll('.main-task-select, .subtask-select').forEach(select => {
                        select.addEventListener('change', function() {
                            const row = this.closest('.task-row');
                            toggleTimesheetSection(row);
                        });
                    });

                    // Update timesheet date when global date changes
                    const globalDateInput = document.querySelector('#global-date-input');
                    if (globalDateInput) {
                        globalDateInput.addEventListener('change', function() {
                            document.querySelectorAll('.timesheet-date').forEach(dateInput => {
                                const row = dateInput.closest('.task-row');
                                const mainTaskSelect = row.querySelector('.main-task-select');
                                if (mainTaskSelect && mainTaskSelect.value && !dateInput.value) {
                                    dateInput.value = this.value;
                                }
                            });
                        });
                    }

                    // Initialize: Hide all subtasks on page load
                    document.querySelectorAll('.subtask-select').forEach(subtaskSelect => {
                        const subtaskOptions = subtaskSelect.querySelectorAll('option');
                        subtaskOptions.forEach(option => {
                            if (option.value === '') {
                                option.style.display = '';
                            } else {
                                option.style.display = 'none';
                            }
                        });
                    });

                    function fetchTaskDetails(row, taskId) {
        if (!taskId) return;

        fetch(`/get_task_details?task_id=${taskId}`)
            .then(response => response.json())
            .then(data => {
                row.querySelector('.task-desc').value = data.description || '';
                row.querySelector('.planned-qty').value = data.planned_quantity || '';
                row.querySelector('.unit').value = data.unit || '';
            });
    }

    // Handle global project selection change - filter main tasks for all rows
    document.querySelector('#global-project-select').addEventListener('change', function (e) {
        const selectedProjectId = e.target.value;

        // Update all task rows
        document.querySelectorAll('.task-row').forEach(row => {
            const mainTaskSelect = row.querySelector('.main-task-select');
            const subtaskSelect = row.querySelector('.subtask-select');

            // Reset main task and subtask selections
            mainTaskSelect.value = '';
            subtaskSelect.value = '';

            // Show/hide main tasks based on selected project
            const mainTaskOptions = mainTaskSelect.querySelectorAll('option');
            mainTaskOptions.forEach(option => {
                if (option.value === '') {
                    option.style.display = '';
                } else {
                    const taskProjectId = option.getAttribute('data-project-id');
                    if (selectedProjectId === '' || taskProjectId === selectedProjectId) {
                        option.style.display = '';
                    } else {
                        option.style.display = 'none';
                    }
                }
            });

            // Hide all subtasks initially (will show when main task is selected)
            const subtaskOptions = subtaskSelect.querySelectorAll('option');
            subtaskOptions.forEach(option => {
                if (option.value === '') {
                    option.style.display = '';
                } else {
                    option.style.display = 'none';
                }
            });
        });
    });

    // Handle task-specific selections
    document.querySelector('#taskRowsContainer').addEventListener('change', function (e) {
        // Handle main task selection change - filter subtasks
        if (e.target.classList.contains('main-task-select')) {
            const row = e.target.closest('.task-row');
            const subtaskSelect = row.querySelector('.subtask-select');
            const selectedMainTaskId = e.target.value;
            const globalProjectSelect = document.querySelector('#global-project-select');
            const selectedProjectId = globalProjectSelect.value;

            // Reset subtask selection
            subtaskSelect.value = '';

            // Show/hide subtasks based on selected main task and project
            const subtaskOptions = subtaskSelect.querySelectorAll('option');
            subtaskOptions.forEach(option => {
                if (option.value === '') {
                    option.style.display = '';
                } else {
                    const subtaskProjectId = option.getAttribute('data-project-id');
                    const subtaskParentId = option.getAttribute('data-parent-id');
                    if (selectedMainTaskId && selectedProjectId && 
                        subtaskParentId === selectedMainTaskId && 
                        subtaskProjectId === selectedProjectId) {
                        option.style.display = '';
                    } else {
                        option.style.display = 'none';
                    }
                }
            });
        }

        // Handle subtask selection change
        if (e.target.classList.contains('subtask-select')) {
            const row = e.target.closest('.task-row');
            fetchTaskDetails(row, e.target.value);
        }
    });

    // Add new task row
    document.querySelector('#addTaskBtn').addEventListener('click', function () {
        const container = document.querySelector('#taskRowsContainer');
        const firstRow = container.querySelector('.task-row');
        const newRow = firstRow.cloneNode(true);
        const rowIndex = container.querySelectorAll('.task-row').length;

        // Reset all inputs (excluding project/date which are global)
        newRow.querySelectorAll('input, textarea, select').forEach(el => {
            // Skip if it's project or date field (shouldn't be in task-row, but just in case)
            if (!el.id || (el.id !== 'global-project-select' && el.id !== 'global-date-input')) {
                // Keep default value for timesheet workers
                if (el.classList.contains('timesheet-workers')) {
                    el.value = '1';
                } else {
                    el.value = '';
                }
            }
        });

        // Update file input name to include row index
        const fileInput = newRow.querySelector('.task-image-input');
        if (fileInput) {
            fileInput.name = `task_images_${rowIndex}_0[]`;
        }

        // Apply global project filter to new row's main tasks
        const globalProjectSelect = document.querySelector('#global-project-select');
        const selectedProjectId = globalProjectSelect.value;
        const mainTaskSelect = newRow.querySelector('.main-task-select');
        if (selectedProjectId) {
            const mainTaskOptions = mainTaskSelect.querySelectorAll('option');
            mainTaskOptions.forEach(option => {
                if (option.value === '') {
                    option.style.display = '';
                } else {
                    const taskProjectId = option.getAttribute('data-project-id');
                    if (taskProjectId === selectedProjectId) {
                        option.style.display = '';
                    } else {
                        option.style.display = 'none';
                    }
                }
            });
        }

        // Hide all subtasks initially
        const subtaskSelect = newRow.querySelector('.subtask-select');
        const subtaskOptions = subtaskSelect.querySelectorAll('option');
        subtaskOptions.forEach(option => {
            if (option.value === '') {
                option.style.display = '';
            } else {
                option.style.display = 'none';
            }
        });

        // Hide timesheet section initially for new row
        const newTimesheetSection = newRow.querySelector('.timesheet-section');
        if (newTimesheetSection) {
            newTimesheetSection.style.display = 'none';
        }

        // Add event listeners for main task and subtask changes in new row
        const newMainTaskSelect = newRow.querySelector('.main-task-select');
        if (newMainTaskSelect) {
            newMainTaskSelect.addEventListener('change', function() {
                toggleTimesheetSection(newRow);
            });
        }
        if (subtaskSelect) {
            subtaskSelect.addEventListener('change', function() {
                toggleTimesheetSection(newRow);
            });
        }

        container.appendChild(newRow);
    });

    // Remove task row
    document.querySelector('#taskRowsContainer').addEventListener('click', function (e) {
        if (e.target.classList.contains('remove-task-btn')) {
            const rows = document.querySelectorAll('.task-row');
            if (rows.length > 1) {
                e.target.closest('.task-row').remove();
            }
        }
    });

    // Validate and limit images on file input change
    document.querySelector('#taskRowsContainer').addEventListener('change', function (e) {
        if (e.target.classList.contains('task-image-input')) {
            const files = e.target.files;
            if (files.length > 10) {
                alert('Maximum 10 images allowed. Please select 10 or fewer images.');
                e.target.value = '';
                return;
            }
        }
    });

    // Handle delete report button click
    document.addEventListener('click', function (e) {
        if (e.target.closest('.delete-report-btn')) {
            const btn = e.target.closest('.delete-report-btn');
            const batchId = btn.getAttribute('data-batch-id');
            const accordionItem = btn.closest('.accordion-item');

            if (confirm('Are you sure you want to delete this progress report? This action cannot be undone.')) {
                // Disable button to prevent double-click
                btn.disabled = true;
                btn.innerHTML = '';

                // Send delete request using Odoo's JSON-RPC format
                fetch(`/my/progress_reports/delete/${batchId}`, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        jsonrpc: '2.0',
                        method: 'call',
                        params: {},
                        id: Math.floor(Math.random() * 1000000)
                    }),
                    credentials: 'same-origin'
                })
                .then(response => response.json())
                .then(data => {
                    // Handle Odoo JSON-RPC response format
                    const result = data.result || data;
                    if (result.success) {
                        // Remove the accordion item with fade animation
                        accordionItem.style.transition = 'opacity 0.3s';
                        accordionItem.style.opacity = '0';
                        setTimeout(() => {
                            accordionItem.remove();
                            // Show message if no reports left
                            const remainingItems = document.querySelectorAll('.accordion-item');
                            if (remainingItems.length === 0) {
                                const accordion = document.querySelector('#dailyReportsAccordion');
                                if (accordion) {
                                    accordion.innerHTML = '
Submitted Progress Reports
No progress reports submitted yet.';
                                }
                            }
                        }, 300);
                    } else {
                        alert(result.error || 'Failed to delete report. Please try again.');
                        btn.disabled = false;
                        btn.innerHTML = '';
                    }
                })
                .catch(error => {
                    console.error('Error:', error);
                    alert('An error occurred while deleting the report. Please try again.');
                    btn.disabled = false;
                    btn.innerHTML = '';
                });
            }
        }
    });
            });
